        new() { Category = "Fall Protection", Description = "Personal fall arrest systems available" },

        // Scaffolding
        new() { Category = "Scaffolding", Description = "Scaffold erected on stable footing" },
        new() { Category = "Scaffolding", Description = "Guardrails and toeboards installed" },
        new() { Category = "Scaffolding", Description = "Access ladders provided" },
        new() { Category = "Scaffolding", Description = "Scaffold inspected by competent person" },

        // Electrical
        new() { Category = "Electrical", Description = "GFCI protection on all temporary circuits" },
        new() { Category = "Electrical", Description = "Electrical panels accessible and labeled" },
        new() { Category = "Electrical", Description = "Extension cords in good condition" },
        new() { Category = "Electrical", Description = "Lockout/tagout procedures followed" },

        // Excavation
        new() { Category = "Excavation", Description = "Excavation walls sloped or shored" },
        new() { Category = "Excavation", Description = "Spoil pile set back from edge (≥2 ft)" },
        new() { Category = "Excavation", Description = "Means of egress provided (ladder within 25 ft)" },
        new() { Category = "Excavation", Description = "Underground utilities located and marked" },

        // Housekeeping
        new() { Category = "Housekeeping", Description = "Work areas free of debris and tripping hazards" },
        new() { Category = "Housekeeping", Description = "Materials stored and stacked safely" },
        new() { Category = "Housekeeping", Description = "Walkways and access routes clear" },
        new() { Category = "Housekeeping", Description = "Waste disposed of properly" },

