const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbManager = {
    initialize: async function () {
        await openDb();
        return true;
    },

    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(JSON.parse(item));
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(key);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(key);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPendingSyncCount: async function () {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const index = tx.objectStore('inspections').index('syncStatus');
            const request = index.count('Pending');
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityManager = {
    isOnline: function () {
        return navigator.onLine;
    },

    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => {
            dotNetRef.invokeMethodAsync('OnConnectivityChanged', true);
        });
        window.addEventListener('offline', () => {
            dotNetRef.invokeMethodAsync('OnConnectivityChanged', false);
        });
    }
};

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync() =>
        await _js.InvokeVoidAsync("indexedDbManager.initialize");

    // Sites
    public async Task SaveSiteAsync(ConstructionSite site) =>
        await _js.InvokeVoidAsync("indexedDbManager.putItem", "sites",
            JsonSerializer.Serialize(site, JsonOptions));

    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbManager.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json, JsonOptions) ?? new();
    }

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbManager.deleteItem", "sites", id);

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.LastModified = DateTime.UtcNow;
        await _js.InvokeVoidAsync("indexedDbManager.putItem", "inspections",
            JsonSerializer.Serialize(inspection, JsonOptions));
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbManager.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("indexedDbManager.getItemsByIndex",
            "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbManager.getItem", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task DeleteInspectionAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbManager.deleteItem", "inspections", id);

    public async Task<int> GetPendingSyncCountAsync() =>
        await _js.InvokeAsync<int>("indexedDbManager.getPendingSyncCount");
}

using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _selfRef;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; }
    public int PendingCount { get; private set; }

    public SyncService(IndexedDbService db, HttpClient http, IJSRuntime js)
    {
        _db = db;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        IsOnline = await _js.InvokeAsync<bool>("connectivityManager.isOnline");
        _selfRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityManager.registerOnlineHandler", _selfRef);
        await UpdatePendingCountAsync();

        // Periodic sync attempt every 30 seconds
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null,
            TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        if (isOnline)
        {
            await TrySyncAsync();
        }
        OnSyncStatusChanged?.Invoke();
    }

    public async Task TrySyncAsync()
    {
        if (!IsOnline) return;

        try
        {
            var inspections = await _db.GetAllInspectionsAsync();
            var pending = inspections.Where(i => i.SyncStatus == SyncStatus.Pending).ToList();

            foreach (var inspection in pending)
            {
                try
                {
                    // Attempt to sync to server
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.SyncStatus = SyncStatus.Synced;
                        await _db.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    // Server unavailable — will retry on next cycle
                }
            }
        }
        catch
        {
            // IndexedDB access error — skip this cycle
        }

        await UpdatePendingCountAsync();
        OnSyncStatusChanged?.Invoke();
    }

    private async Task UpdatePendingCountAsync()
    {
        try { PendingCount = await _db.GetPendingSyncCountAsync(); }
        catch { /* ignore */ }
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _selfRef?.Dispose();
    }
}

