using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync() =>
        await _js.InvokeVoidAsync("indexedDbManager.initialize");

    // Sites
    public async Task SaveSiteAsync(ConstructionSite site) =>
        await _js.InvokeVoidAsync("indexedDbManager.putItem", "sites",
            JsonSerializer.Serialize(site, JsonOptions));

    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbManager.getAllItems", "sites");
        return JsonSerializer.Deserialize<List<ConstructionSite>>(json, JsonOptions) ?? new();
    }

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbManager.deleteItem", "sites", id);

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.LastModified = DateTime.UtcNow;
        await _js.InvokeVoidAsync("indexedDbManager.putItem", "inspections",
            JsonSerializer.Serialize(inspection, JsonOptions));
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("indexedDbManager.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("indexedDbManager.getItemsByIndex",
            "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbManager.getItem", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task DeleteInspectionAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbManager.deleteItem", "inspections", id);

    public async Task<int> GetPendingSyncCountAsync() =>
        await _js.InvokeAsync<int>("indexedDbManager.getPendingSyncCount");
}

