using System.Net.Http.Json;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _db;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _selfRef;
    private Timer? _syncTimer;

    public event Action? OnSyncStatusChanged;
    public bool IsOnline { get; private set; }
    public int PendingCount { get; private set; }

    public SyncService(IndexedDbService db, HttpClient http, IJSRuntime js)
    {
        _db = db;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        IsOnline = await _js.InvokeAsync<bool>("connectivityManager.isOnline");
        _selfRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityManager.registerOnlineHandler", _selfRef);
        await UpdatePendingCountAsync();

        // Periodic sync attempt every 30 seconds
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null,
            TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        if (isOnline)
        {
            await TrySyncAsync();
        }
        OnSyncStatusChanged?.Invoke();
    }

    public async Task TrySyncAsync()
    {
        if (!IsOnline) return;

        try
        {
            var inspections = await _db.GetAllInspectionsAsync();
            var pending = inspections.Where(i => i.SyncStatus == SyncStatus.Pending).ToList();

            foreach (var inspection in pending)
            {
                try
                {
                    // Attempt to sync to server
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.SyncStatus = SyncStatus.Synced;
                        await _db.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    // Server unavailable — will retry on next cycle
                }
            }
        }
        catch
        {
            // IndexedDB access error — skip this cycle
        }

        await UpdatePendingCountAsync();
        OnSyncStatusChanged?.Invoke();
    }

    private async Task UpdatePendingCountAsync()
    {
        try { PendingCount = await _db.GetPendingSyncCountAsync(); }
        catch { /* ignore */ }
    }

    public void Dispose()
    {
        _syncTimer?.Dispose();
        _selfRef?.Dispose();
    }
}

