@page "/"
@inject SiteInspector.Services.IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <p class="subtitle">Construction Safety Inspections</p>
</div>

<div class="action-cards">
    <div class="action-card" @onclick='() => Nav.NavigateTo("/sites")'>
        <div class="card-icon">📋</div>
        <div class="card-title">My Sites</div>
        <div class="card-desc">@(_siteCount) site(s) registered</div>
    </div>

    <div class="action-card" @onclick='() => Nav.NavigateTo("/inspections")'>
        <div class="card-icon">🔍</div>
        <div class="card-title">Inspections</div>
        <div class="card-desc">@(_inspectionCount) inspection(s)</div>
    </div>

    <div class="action-card primary" @onclick="StartQuickInspection">
        <div class="card-icon">⚡</div>
        <div class="card-title">Quick Inspection</div>
        <div class="card-desc">Start a new inspection now</div>
    </div>
</div>

@if (_recentInspections.Any())
{
    <div class="section-header">Recent Inspections</div>
    <div class="recent-list">
        @foreach (var inspection in _recentInspections)
        {
            <div class="recent-item" @onclick="() => OpenInspection(inspection.Id)">
                <div class="recent-info">
                    <strong>@inspection.SiteName</strong>
                    <span class="recent-date">@inspection.InspectionDate.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                </div>
                <div class="recent-status @inspection.Status.ToString().ToLower()">
                    @(inspection.Status == InspectionStatus.Completed ? "✓" : "…")
                </div>
            </div>
        }
    </div>
}

@code {
    private int _siteCount;
    private int _inspectionCount;
    private List<Inspection> _recentInspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Db.GetAllSitesAsync();
        _siteCount = sites.Count;
        var inspections = await Db.GetAllInspectionsAsync();
        _inspectionCount = inspections.Count;
        _recentInspections = inspections.OrderByDescending(i => i.LastModified).Take(5).ToList();
    }

    private async Task StartQuickInspection()
    {
        var sites = await Db.GetAllSitesAsync();
        if (sites.Any())
        {
            Nav.NavigateTo($"/inspection/new/{sites.First().Id}");
        }
        else
        {
            Nav.NavigateTo("/sites");
        }
    }

    private void OpenInspection(string id) => Nav.NavigateTo($"/inspection/{id}");
}

@page "/sites"
@inject SiteInspector.Services.IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header compact">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h2>Construction Sites</h2>
</div>

@if (_showForm)
{
    <div class="form-card">
        <div class="form-group">
            <label>Site Name</label>
            <input type="text" @bind="_newSite.Name" @bind:event="oninput" placeholder="e.g. Oak Street Tower" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input type="text" @bind="_newSite.Address" @bind:event="oninput" placeholder="123 Main St" />
        </div>
        <div class="form-actions">
            <button class="btn-secondary" @onclick="CancelAdd">Cancel</button>
            <button class="btn-primary" @onclick="SaveSite" disabled="@string.IsNullOrWhiteSpace(_newSite.Name)">Save Site</button>
        </div>
    </div>
}
else
{
    <button class="btn-add" @onclick="ShowAddForm">+ Add New Site</button>
}

<div class="site-list">
    @foreach (var site in _sites)
    {
        <div class="site-card">
            <div class="site-info" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </div>
            <button class="btn-inspect" @onclick="() => Nav.NavigateTo($&quot;/inspection/new/{site.Id}&quot;)">
                Inspect
            </button>
        </div>
    }
</div>

@if (!_sites.Any() && !_showForm)
{
    <div class="empty-state">
        <p>No sites added yet. Tap "Add New Site" to get started.</p>
    </div>
}

@code {
    private List<ConstructionSite> _sites = new();
    private ConstructionSite _newSite = new();
    private bool _showForm;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Db.GetAllSitesAsync();
    }

    private void ShowAddForm() => _showForm = true;
    private void CancelAdd() { _showForm = false; _newSite = new(); }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(_newSite.Name)) return;
        await Db.SaveSiteAsync(_newSite);
        _sites.Insert(0, _newSite);
        _newSite = new();
        _showForm = false;
    }
}

@page "/site/{SiteId}"
@inject SiteInspector.Services.IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header compact">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/sites")'>← Back</button>
    <h2>@(_site?.Name ?? "Site")</h2>
</div>

@if (_site is not null)
{
    <div class="site-detail">
        <p class="site-address">📍 @_site.Address</p>
        <button class="btn-primary full-width" @onclick="StartInspection">
            + New Inspection
        </button>
    </div>

    <div class="section-header">Past Inspections (@_inspections.Count)</div>
    <div class="inspection-list">
        @foreach (var insp in _inspections)
        {
            <div class="inspection-item" @onclick="() => Nav.NavigateTo($&quot;/inspection/{insp.Id}&quot;)">
                <div class="inspection-info">
                    <span class="inspection-date">@insp.InspectionDate.ToLocalTime().ToString("MMM dd yyyy, HH:mm")</span>
                    <span class="inspection-inspector">@insp.InspectorName</span>
                </div>
                <div class="inspection-badges">
                    <span class="badge @insp.Status.ToString().ToLower()">@insp.Status</span>
                    <span class="badge sync-@insp.SyncStatus.ToString().ToLower()">@(insp.SyncStatus == SyncStatus.Synced ? "☁️" : "📱")</span>
                </div>
            </div>
        }
    </div>

    @if (!_inspections.Any())
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Db.GetAllSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = (await Db.GetInspectionsBySiteAsync(SiteId))
            .OrderByDescending(i => i.InspectionDate).ToList();
    }

    private void StartInspection() => Nav.NavigateTo($"/inspection/new/{SiteId}");
}

@page "/inspection/new/{SiteId}"
@page "/inspection/{InspectionId}"
@inject SiteInspector.Services.IndexedDbService Db
@inject SiteInspector.Services.SyncService Sync
@inject NavigationManager Nav

<div class="page-header compact">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h2>@(_isNew ? "New Inspection" : "Inspection")</h2>
    @if (_inspection is not null && _inspection.Status == InspectionStatus.InProgress)
    {
        <button class="btn-complete" @onclick="CompleteInspection">✓ Complete</button>
    }
</div>

@if (_inspection is not null)
{
    <div class="inspector-field">
        <input type="text" @bind="_inspection.InspectorName" @bind:event="oninput"
               @onblur="AutoSave" placeholder="Inspector name" />
    </div>

    <!-- Tab Navigation -->
    <div class="tab-bar">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist
            <span class="tab-badge">@CompletedCount/@_inspection.Checklist.Count</span>
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos
            <span class="tab-badge">@_inspection.Photos.Count</span>
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist-container">
            @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <div class="category-header" @onclick="() => ToggleCategory(category.Key)">
                        <span>@category.Key</span>
                        <span class="category-progress">
                            @category.Count(c => c.Result != CheckResult.NotChecked)/@category.Count()
                        </span>
                    </div>
                    @if (IsCategoryExpanded(category.Key))
                    {
                        @foreach (var item in category)
                        {
                            <div class="checklist-item @item.Result.ToString().ToLower()">
                                <div class="item-description">@item.Description</div>
                                <div class="item-actions">
                                    <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                    <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                    <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                                </div>
                                @if (item.Result == CheckResult.Fail || !string.IsNullOrEmpty(item.Notes))
                                {
                                    <div class="item-notes">
                                        <input type="text" @bind="item.Notes" @bind:event="oninput"
                                               @onblur="AutoSave" placeholder="Add note..." />
                                    </div>
                                }
                            </div>
                        }
                    }
                </div>
            }
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-container">
            <label class="photo-upload-btn">
                📷 Take / Add Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" />
            </label>

            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos)
                {
                    <div class="photo-card">
                        <img src="@photo.DataUrl" alt="@photo.Caption" />
                        <input type="text" @bind="photo.Caption" @bind:event="oninput"
                               @onblur="AutoSave" placeholder="Caption..." />
                        <button class="photo-delete" @onclick="() => RemovePhoto(photo)">🗑️</button>
                    </div>
                }
            </div>

            @if (!_inspection.Photos.Any())
            {
                <div class="empty-state">
                    <p>No photos attached. Tap the button above to add photos.</p>
                </div>
            }
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-container">
            <textarea @bind="_inspection.GeneralNotes" @bind:event="oninput"
                      @onblur="AutoSave" placeholder="General observations, concerns, action items..."
                      rows="10"></textarea>
        </div>
    }
}

@code {
    [Parameter] public string? SiteId { get; set; }
    [Parameter] public string? InspectionId { get; set; }

    private Inspection? _inspection;
    private bool _isNew;
    private string _activeTab = "checklist";
    private HashSet<string> _expandedCategories = new() { "Fall Protection" };
    private int CompletedCount => _inspection?.Checklist.Count(c => c.Result != CheckResult.NotChecked) ?? 0;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(InspectionId))
        {
            _inspection = await Db.GetInspectionAsync(InspectionId);
            _isNew = false;
        }
        else if (!string.IsNullOrEmpty(SiteId))
        {
            var sites = await Db.GetAllSitesAsync();
            var site = sites.FirstOrDefault(s => s.Id == SiteId);
            _inspection = new Inspection
            {
                SiteId = SiteId,
                SiteName = site?.Name ?? "Unknown Site",
                Checklist = ChecklistTemplates.GetStandardChecklist()
            };
            _isNew = true;
            await Db.SaveInspectionAsync(_inspection);
        }
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = (item.Result == result) ? CheckResult.NotChecked : result;
        await AutoSave();
    }

    private void ToggleCategory(string category)
    {
        if (!_expandedCategories.Remove(category))
            _expandedCategories.Add(category);
    }

    private bool IsCategoryExpanded(string category) => _expandedCategories.Contains(category);

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // 10 MB limit

            var buffer = new byte[file.Size];
            await file.OpenReadStream(10 * 1024 * 1024).ReadAsync(buffer);
            var dataUrl = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";

            _inspection!.Photos.Add(new PhotoRecord
            {
                FileName = file.Name,
                DataUrl = dataUrl
            });
        }
        await AutoSave();
    }

    private async Task RemovePhoto(PhotoRecord photo)
    {
        _inspection!.Photos.Remove(photo);
        await AutoSave();
    }

    private async Task AutoSave()
    {
        if (_inspection is null) return;
        _inspection.SyncStatus = SyncStatus.Pending;
        await Db.SaveInspectionAsync(_inspection);
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        await AutoSave();
        await Sync.TrySyncAsync();
        GoBack();
    }

    private void GoBack()
    {
        if (!string.IsNullOrEmpty(SiteId))
            Nav.NavigateTo($"/site/{SiteId}");
        else if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}

@page "/inspections"
@inject SiteInspector.Services.IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header compact">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h2>All Inspections</h2>
</div>

<div class="filter-bar">
    <button class="filter-btn @(_filter == "all" ? "active" : "")" @onclick='() => _filter = "all"'>All</button>
    <button class="filter-btn @(_filter == "inprogress" ? "active" : "")" @onclick='() => _filter = "inprogress"'>In Progress</button>
    <button class="filter-btn @(_filter == "completed" ? "active" : "")" @onclick='() => _filter = "completed"'>Completed</button>
    <button class="filter-btn @(_filter == "pending" ? "active" : "")" @onclick='() => _filter = "pending"'>Unsynced</button>
</div>

<div class="inspection-list">
    @foreach (var insp in FilteredInspections)
    {
        <div class="inspection-item" @onclick="() => Nav.NavigateTo($&quot;/inspection/{insp.Id}&quot;)">
            <div class="inspection-info">
                <strong>@insp.SiteName</strong>
                <span class="inspection-date">@insp.InspectionDate.ToLocalTime().ToString("MMM dd yyyy, HH:mm")</span>
                <span class="inspection-inspector">@insp.InspectorName</span>
            </div>
            <div class="inspection-badges">
                <span class="badge @insp.Status.ToString().ToLower()">@insp.Status</span>
                <span class="badge sync-@insp.SyncStatus.ToString().ToLower()">
                    @(insp.SyncStatus == SyncStatus.Synced ? "☁️ Synced" : "📱 Local")
                </span>
            </div>
        </div>
    }
</div>

@if (!FilteredInspections.Any())
{
    <div class="empty-state">
        <p>No inspections match the current filter.</p>
    </div>
}

@code {
    private List<Inspection> _inspections = new();
    private string _filter = "all";

    private IEnumerable<Inspection> FilteredInspections => _filter switch
    {
        "inprogress" => _inspections.Where(i => i.Status == InspectionStatus.InProgress),
        "completed" => _inspections.Where(i => i.Status == InspectionStatus.Completed),
        "pending" => _inspections.Where(i => i.SyncStatus == SyncStatus.Pending),
