@page "/inspection/{InspectionId}"
@inject SiteInspector.Services.IndexedDbService Db
@inject SiteInspector.Services.SyncService Sync
@inject NavigationManager Nav

<div class="page-header compact">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h2>@(_isNew ? "New Inspection" : "Inspection")</h2>
    @if (_inspection is not null && _inspection.Status == InspectionStatus.InProgress)
    {
        <button class="btn-complete" @onclick="CompleteInspection">✓ Complete</button>
    }
</div>

@if (_inspection is not null)
{
    <div class="inspector-field">
        <input type="text" @bind="_inspection.InspectorName" @bind:event="oninput"
               @onblur="AutoSave" placeholder="Inspector name" />
    </div>

    <!-- Tab Navigation -->
    <div class="tab-bar">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist
            <span class="tab-badge">@CompletedCount/@_inspection.Checklist.Count</span>
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos
            <span class="tab-badge">@_inspection.Photos.Count</span>
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist-container">
            @foreach (var category in _inspection.Checklist.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <div class="category-header" @onclick="() => ToggleCategory(category.Key)">
                        <span>@category.Key</span>
                        <span class="category-progress">
                            @category.Count(c => c.Result != CheckResult.NotChecked)/@category.Count()
                        </span>
                    </div>
                    @if (IsCategoryExpanded(category.Key))
                    {
                        @foreach (var item in category)
                        {
                            <div class="checklist-item @item.Result.ToString().ToLower()">
                                <div class="item-description">@item.Description</div>
                                <div class="item-actions">
                                    <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Pass)">✓</button>
                                    <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.Fail)">✗</button>
                                    <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                            @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                                </div>
                                @if (item.Result == CheckResult.Fail || !string.IsNullOrEmpty(item.Notes))
                                {
                                    <div class="item-notes">
                                        <input type="text" @bind="item.Notes" @bind:event="oninput"
                                               @onblur="AutoSave" placeholder="Add note..." />
                                    </div>
                                }
                            </div>
                        }
                    }
                </div>
            }
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-container">
            <label class="photo-upload-btn">
                📷 Take / Add Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" />
            </label>

            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos)
                {
                    <div class="photo-card">
                        <img src="@photo.DataUrl" alt="@photo.Caption" />
                        <input type="text" @bind="photo.Caption" @bind:event="oninput"
                               @onblur="AutoSave" placeholder="Caption..." />
                        <button class="photo-delete" @onclick="() => RemovePhoto(photo)">🗑️</button>
                    </div>
                }
            </div>

            @if (!_inspection.Photos.Any())
            {
                <div class="empty-state">
                    <p>No photos attached. Tap the button above to add photos.</p>
                </div>
            }
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-container">
            <textarea @bind="_inspection.GeneralNotes" @bind:event="oninput"
                      @onblur="AutoSave" placeholder="General observations, concerns, action items..."
                      rows="10"></textarea>
        </div>
    }
}

@code {
    [Parameter] public string? SiteId { get; set; }
    [Parameter] public string? InspectionId { get; set; }

    private Inspection? _inspection;
    private bool _isNew;
    private string _activeTab = "checklist";
    private HashSet<string> _expandedCategories = new() { "Fall Protection" };
    private int CompletedCount => _inspection?.Checklist.Count(c => c.Result != CheckResult.NotChecked) ?? 0;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(InspectionId))
        {
            _inspection = await Db.GetInspectionAsync(InspectionId);
            _isNew = false;
        }
        else if (!string.IsNullOrEmpty(SiteId))
        {
            var sites = await Db.GetAllSitesAsync();
            var site = sites.FirstOrDefault(s => s.Id == SiteId);
            _inspection = new Inspection
            {
                SiteId = SiteId,
                SiteName = site?.Name ?? "Unknown Site",
                Checklist = ChecklistTemplates.GetStandardChecklist()
            };
            _isNew = true;
            await Db.SaveInspectionAsync(_inspection);
        }
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = (item.Result == result) ? CheckResult.NotChecked : result;
        await AutoSave();
    }

    private void ToggleCategory(string category)
    {
        if (!_expandedCategories.Remove(category))
            _expandedCategories.Add(category);
    }

    private bool IsCategoryExpanded(string category) => _expandedCategories.Contains(category);

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // 10 MB limit

            var buffer = new byte[file.Size];
            await file.OpenReadStream(10 * 1024 * 1024).ReadAsync(buffer);
            var dataUrl = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";

            _inspection!.Photos.Add(new PhotoRecord
            {
                FileName = file.Name,
                DataUrl = dataUrl
            });
        }
        await AutoSave();
    }

    private async Task RemovePhoto(PhotoRecord photo)
    {
        _inspection!.Photos.Remove(photo);
        await AutoSave();
    }

    private async Task AutoSave()
    {
        if (_inspection is null) return;
        _inspection.SyncStatus = SyncStatus.Pending;
        await Db.SaveInspectionAsync(_inspection);
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        await AutoSave();
        await Sync.TrySyncAsync();
        GoBack();
    }

    private void GoBack()
    {
        if (!string.IsNullOrEmpty(SiteId))
            Nav.NavigateTo($"/site/{SiteId}");
        else if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}
