@inject SiteInspector.Services.IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header compact">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h2>Construction Sites</h2>
</div>

@if (_showForm)
{
    <div class="form-card">
        <div class="form-group">
            <label>Site Name</label>
            <input type="text" @bind="_newSite.Name" @bind:event="oninput" placeholder="e.g. Oak Street Tower" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input type="text" @bind="_newSite.Address" @bind:event="oninput" placeholder="123 Main St" />
        </div>
        <div class="form-actions">
            <button class="btn-secondary" @onclick="CancelAdd">Cancel</button>
            <button class="btn-primary" @onclick="SaveSite" disabled="@string.IsNullOrWhiteSpace(_newSite.Name)">Save Site</button>
        </div>
    </div>
}
else
{
    <button class="btn-add" @onclick="ShowAddForm">+ Add New Site</button>
}

<div class="site-list">
    @foreach (var site in _sites)
    {
        <div class="site-card">
            <div class="site-info" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </div>
            <button class="btn-inspect" @onclick="() => Nav.NavigateTo($&quot;/inspection/new/{site.Id}&quot;)">
                Inspect
            </button>
        </div>
    }
</div>

@if (!_sites.Any() && !_showForm)
{
    <div class="empty-state">
        <p>No sites added yet. Tap "Add New Site" to get started.</p>
    </div>
}

@code {
    private List<ConstructionSite> _sites = new();
    private ConstructionSite _newSite = new();
    private bool _showForm;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Db.GetAllSitesAsync();
    }

    private void ShowAddForm() => _showForm = true;
    private void CancelAdd() { _showForm = false; _newSite = new(); }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(_newSite.Name)) return;
        await Db.SaveSiteAsync(_newSite);
        _sites.Insert(0, _newSite);
        _newSite = new();
        _showForm = false;
    }
}

