@page "/"
@inject SiteInspector.Services.IndexedDbService Db
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
    <p class="subtitle">Construction Safety Inspections</p>
</div>

<div class="action-cards">
    <div class="action-card" @onclick='() => Nav.NavigateTo("/sites")'>
        <div class="card-icon">📋</div>
        <div class="card-title">My Sites</div>
        <div class="card-desc">@(_siteCount) site(s) registered</div>
    </div>

    <div class="action-card" @onclick='() => Nav.NavigateTo("/inspections")'>
        <div class="card-icon">🔍</div>
        <div class="card-title">Inspections</div>
        <div class="card-desc">@(_inspectionCount) inspection(s)</div>
    </div>

    <div class="action-card primary" @onclick="StartQuickInspection">
        <div class="card-icon">⚡</div>
        <div class="card-title">Quick Inspection</div>
        <div class="card-desc">Start a new inspection now</div>
    </div>
</div>

@if (_recentInspections.Any())
{
    <div class="section-header">Recent Inspections</div>
    <div class="recent-list">
        @foreach (var inspection in _recentInspections)
        {
            <div class="recent-item" @onclick="() => OpenInspection(inspection.Id)">
                <div class="recent-info">
                    <strong>@inspection.SiteName</strong>
                    <span class="recent-date">@inspection.InspectionDate.ToLocalTime().ToString("MMM dd, HH:mm")</span>
                </div>
                <div class="recent-status @inspection.Status.ToString().ToLower()">
                    @(inspection.Status == InspectionStatus.Completed ? "✓" : "…")
                </div>
            </div>
        }
    </div>
}

@code {
    private int _siteCount;
    private int _inspectionCount;
    private List<Inspection> _recentInspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Db.GetAllSitesAsync();
        _siteCount = sites.Count;
        var inspections = await Db.GetAllInspectionsAsync();
        _inspectionCount = inspections.Count;
        _recentInspections = inspections.OrderByDescending(i => i.LastModified).Take(5).ToList();
    }

    private async Task StartQuickInspection()
    {
        var sites = await Db.GetAllSitesAsync();
        if (sites.Any())
        {
            Nav.NavigateTo($"/inspection/new/{sites.First().Id}");
        }
        else
        {
            Nav.NavigateTo("/sites");
        }
    }

    private void OpenInspection(string id) => Nav.NavigateTo($"/inspection/{id}");
}

