/* Site Inspector - Mobile-First CSS */

:root {
    --primary: #1a73e8;
    --primary-dark: #1557b0;
    --success: #34a853;
    --danger: #ea4335;
    --warning: #fbbc04;
    --gray-50: #f8f9fa;
    --gray-100: #f1f3f4;
    --gray-200: #e8eaed;
    --gray-300: #dadce0;
    --gray-600: #5f6368;
    --gray-800: #3c4043;
    --gray-900: #202124;
    --radius: 12px;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    line-height: 1.5;
    color: var(--gray-900);
    background: var(--gray-50);
    overscroll-behavior: none;
    -webkit-font-smoothing: antialiased;
}

/* App Shell */
.app-shell {
    min-height: 100dvh;
    display: flex;
    flex-direction: column;
}

.status-bar {
    position: sticky;
    top: 0;
    z-index: 100;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 6px 16px;
    background: var(--gray-900);
    color: white;
    font-size: 0.75rem;
}

.connectivity.online { color: var(--success); }
.connectivity.offline { color: var(--danger); }
.pending-badge {
    background: var(--warning);
    color: var(--gray-900);
    padding: 2px 8px;
    border-radius: 10px;
    font-weight: 600;
}

.app-content {
    flex: 1;
    padding: 16px;
    padding-bottom: env(safe-area-inset-bottom, 16px);
    max-width: 600px;
    margin: 0 auto;
    width: 100%;
}

/* Page Header */
.page-header {
    text-align: center;
    padding: 24px 0 16px;
}

.page-header h1 {
    font-size: 1.75rem;
    margin: 0;
}

.page-header.compact {
    display: flex;
    align-items: center;
    gap: 12px;
    text-align: left;
    padding: 8px 0 16px;
}

.page-header.compact h2 {
    font-size: 1.25rem;
    margin: 0;
    flex: 1;
}

.subtitle {
    color: var(--gray-600);
    margin: 4px 0 0;
}

/* Buttons */
.btn-back {
    background: none;
    border: none;
    font-size: 1rem;
    color: var(--primary);
    padding: 8px 0;
    cursor: pointer;
    font-weight: 500;
}

.btn-primary {
    background: var(--primary);
    color: white;
    border: none;
    padding: 12px 24px;
    border-radius: var(--radius);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-primary:hover { background: var(--primary-dark); }
.btn-primary:disabled { opacity: 0.5; cursor: not-allowed; }
.btn-primary.full-width { width: 100%; }

.btn-secondary {
    background: var(--gray-200);
    color: var(--gray-800);
    border: none;
    padding: 12px 24px;
    border-radius: var(--radius);
    font-size: 1rem;
    cursor: pointer;
}

.btn-complete {
    background: var(--success);
    color: white;
    border: none;
    padding: 8px 16px;
    border-radius: var(--radius);
    font-size: 0.875rem;
    font-weight: 600;
    cursor: pointer;
}

.btn-add {
    width: 100%;
    padding: 14px;
    background: white;
    border: 2px dashed var(--gray-300);
    border-radius: var(--radius);
    font-size: 1rem;
    color: var(--primary);
    font-weight: 600;
    cursor: pointer;
    margin-bottom: 16px;
}

.btn-inspect {
    background: var(--primary);
    color: white;
    border: none;
    padding: 8px 16px;
    border-radius: 8px;
    font-size: 0.875rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}

/* Action Cards (Home) */
.action-cards {
    display: grid;
    gap: 12px;
    margin-top: 16px;
}

.action-card {
    background: white;
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: var(--shadow);
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 16px;
    transition: transform 0.1s;
}

.action-card:active { transform: scale(0.98); }

.action-card.primary {
    background: var(--primary);
    color: white;
}

.action-card .card-icon { font-size: 2rem; }
.action-card .card-title { font-size: 1.1rem; font-weight: 600; }
.action-card .card-desc { font-size: 0.85rem; opacity: 0.8; }

/* Section Header */
.section-header {
    font-size: 0.85rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--gray-600);
    margin: 24px 0 8px;
}

/* Recent List */
.recent-list, .inspection-list, .site-list {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.recent-item, .inspection-item {
    background: white;
    border-radius: var(--radius);
    padding: 14px 16px;
    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    transition: transform 0.1s;
}

.recent-item:active, .inspection-item:active { transform: scale(0.98); }

.recent-info, .inspection-info {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.recent-date, .inspection-date {
    font-size: 0.8rem;
    color: var(--gray-600);
}

.inspection-inspector {
    font-size: 0.8rem;
    color: var(--gray-600);
}

.recent-status {
    font-size: 1.2rem;
}

.inspection-badges {
    display: flex;
    flex-direction: column;
    gap: 4px;
    align-items: flex-end;
}

.badge {
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 8px;
    font-weight: 600;
}

.badge.inprogress { background: var(--warning); color: var(--gray-900); }
.badge.completed { background: var(--success); color: white; }
.badge.sync-pending { background: var(--gray-200); }
.badge.sync-synced { background: #e8f5e9; color: var(--success); }

/* Site Cards */
.site-card {
    background: white;
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
}

.site-info { cursor: pointer; flex: 1; }
.site-name { font-weight: 600; font-size: 1rem; }
.site-address { font-size: 0.85rem; color: var(--gray-600); }
.site-detail { margin-bottom: 16px; }
.site-detail .site-address { margin-bottom: 12px; }

/* Forms */
.form-card {
    background: white;
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: var(--shadow);
    margin-bottom: 16px;
}

.form-group {
    margin-bottom: 12px;
}

.form-group label {
    display: block;
    font-size: 0.85rem;
    font-weight: 600;
    margin-bottom: 4px;
    color: var(--gray-600);
}

.form-group input, .inspector-field input, .notes-container textarea {
    width: 100%;
    padding: 12px;
    border: 1px solid var(--gray-300);
    border-radius: 8px;
    font-size: 1rem;
    outline: none;
    transition: border-color 0.15s;
}

.form-group input:focus, .inspector-field input:focus, .notes-container textarea:focus {
    border-color: var(--primary);
}

.form-actions {
    display: flex;
    gap: 8px;
    justify-content: flex-end;
}

.inspector-field {
    margin-bottom: 16px;
}

/* Filter Bar */
.filter-bar {
    display: flex;
    gap: 8px;
    margin-bottom: 16px;
    overflow-x: auto;
    padding-bottom: 4px;
}

