/* Site Inspector - Mobile-First CSS */

:root {
    --primary: #1a73e8;
    --primary-dark: #1557b0;
    --success: #34a853;
    --danger: #ea4335;
    --warning: #fbbc04;
    --gray-50: #f8f9fa;
    --gray-100: #f1f3f4;
    --gray-200: #e8eaed;
    --gray-300: #dadce0;
    --gray-600: #5f6368;
    --gray-800: #3c4043;
    --gray-900: #202124;
    --radius: 12px;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 16px;
    line-height: 1.5;
    color: var(--gray-900);
    background: var(--gray-50);
    overscroll-behavior: none;
    -webkit-font-smoothing: antialiased;
}

/* App Shell */
.app-shell {
    min-height: 100dvh;
    display: flex;
    flex-direction: column;
}

.status-bar {
    position: sticky;
    top: 0;
    z-index: 100;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 6px 16px;
    background: var(--gray-900);
    color: white;
    font-size: 0.75rem;
}

.connectivity.online { color: var(--success); }
.connectivity.offline { color: var(--danger); }
.pending-badge {
    background: var(--warning);
    color: var(--gray-900);
    padding: 2px 8px;
    border-radius: 10px;
    font-weight: 600;
}

.app-content {
    flex: 1;
    padding: 16px;
    padding-bottom: env(safe-area-inset-bottom, 16px);
    max-width: 600px;
    margin: 0 auto;
    width: 100%;
}

/* Page Header */
.page-header {
    text-align: center;
    padding: 24px 0 16px;
}

.page-header h1 {
    font-size: 1.75rem;
    margin: 0;
}

.page-header.compact {
    display: flex;
    align-items: center;
    gap: 12px;
    text-align: left;
    padding: 8px 0 16px;
}

.page-header.compact h2 {
    font-size: 1.25rem;
    margin: 0;
    flex: 1;
}

.subtitle {
    color: var(--gray-600);
    margin: 4px 0 0;
}

