.action-cards {
    display: grid;
    gap: 12px;
    margin-top: 16px;
}

.action-card {
    background: white;
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: var(--shadow);
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 16px;
    transition: transform 0.1s;
