    color: var(--primary);
    padding: 8px 0;
    cursor: pointer;
    font-weight: 500;
}

.btn-primary {
    background: var(--primary);
    color: white;
    border: none;
    padding: 12px 24px;
    border-radius: var(--radius);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-primary:hover { background: var(--primary-dark); }
.btn-primary:disabled { opacity: 0.5; cursor: not-allowed; }
.btn-primary.full-width { width: 100%; }

.btn-secondary {
    background: var(--gray-200);
    color: var(--gray-800);
    border: none;
    padding: 12px 24px;
    border-radius: var(--radius);
    font-size: 1rem;
    cursor: pointer;
}

.btn-complete {
    background: var(--success);
    color: white;
    border: none;
    padding: 8px 16px;
    border-radius: var(--radius);
    font-size: 0.875rem;
    font-weight: 600;
    cursor: pointer;
}

.btn-add {
    width: 100%;
    padding: 14px;
    background: white;
    border: 2px dashed var(--gray-300);
    border-radius: var(--radius);
    font-size: 1rem;
    color: var(--primary);
    font-weight: 600;
    cursor: pointer;
    margin-bottom: 16px;
}

.btn-inspect {
    background: var(--primary);
    color: white;
    border: none;
    padding: 8px 16px;
    border-radius: 8px;
    font-size: 0.875rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}

.action-cards {
    display: grid;
    gap: 12px;
    margin-top: 16px;
}

.action-card {
    background: white;
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: var(--shadow);
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 16px;
    transition: transform 0.1s;
}

.action-card:active { transform: scale(0.98); }

.action-card.primary {
    background: var(--primary);
    color: white;
}

.action-card .card-icon { font-size: 2rem; }
.action-card .card-title { font-size: 1.1rem; font-weight: 600; }
.action-card .card-desc { font-size: 0.85rem; opacity: 0.8; }

.section-header {
    font-size: 0.85rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--gray-600);
    margin: 24px 0 8px;
}

.recent-list, .inspection-list, .site-list {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.recent-item, .inspection-item {
    background: white;
    border-radius: var(--radius);
    padding: 14px 16px;
    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    justify-content: space-between;
    cursor: pointer;
    transition: transform 0.1s;
}

.recent-item:active, .inspection-item:active { transform: scale(0.98); }

.recent-info, .inspection-info {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.recent-date, .inspection-date {
    font-size: 0.8rem;
    color: var(--gray-600);
}

.inspection-inspector {
    font-size: 0.8rem;
    color: var(--gray-600);
}

.recent-status { font-size: 1.2rem; }

.inspection-badges {
    display: flex;
    flex-direction: column;
    gap: 4px;
    align-items: flex-end;
}

.badge {
    font-size: 0.7rem;
    padding: 2px 8px;
    border-radius: 8px;
    font-weight: 600;
}

.badge.inprogress { background: var(--warning); color: var(--gray-900); }
.badge.completed { background: var(--success); color: white; }
.badge.sync-pending { background: var(--gray-200); }
.badge.sync-synced { background: #e8f5e9; color: var(--success); }

.site-card {
    background: white;
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
}

.site-info { cursor: pointer; flex: 1; }
.site-name { font-weight: 600; font-size: 1rem; }
.site-address { font-size: 0.85rem; color: var(--gray-600); }
.site-detail { margin-bottom: 16px; }
.site-detail .site-address { margin-bottom: 12px; }

.form-card {
    background: white;
    border-radius: var(--radius);
    padding: 20px;
    box-shadow: var(--shadow);
    margin-bottom: 16px;
}

.form-group { margin-bottom: 12px; }

.form-group label {
    display: block;
    font-size: 0.85rem;
    font-weight: 600;
    margin-bottom: 4px;
    color: var(--gray-600);
}

.form-group input, .inspector-field input, .notes-container textarea {
    width: 100%;
    padding: 12px;
    border: 1px solid var(--gray-300);
    border-radius: 8px;
    font-size: 1rem;
    outline: none;
    transition: border-color 0.15s;
}

.form-group input:focus, .inspector-field input:focus, .notes-container textarea:focus {
    border-color: var(--primary);
}

.form-actions {
    display: flex;
    gap: 8px;
    justify-content: flex-end;
}

.inspector-field { margin-bottom: 16px; }

.filter-bar {
    display: flex;
    gap: 8px;
    margin-bottom: 16px;
    overflow-x: auto;
    padding-bottom: 4px;
}

.filter-btn {
    background: white;
    border: 1px solid var(--gray-300);
    padding: 8px 14px;
    border-radius: 20px;
    font-size: 0.85rem;
    white-space: nowrap;
    cursor: pointer;
}

.filter-btn.active {
    background: var(--primary);
    color: white;
    border-color: var(--primary);
}

.tab-bar {
    display: flex;
    border-bottom: 2px solid var(--gray-200);
    margin-bottom: 16px;
}

.tab {
    flex: 1;
    padding: 12px 8px;
    background: none;
    border: none;
    font-size: 0.9rem;
    font-weight: 600;
    color: var(--gray-600);
    cursor: pointer;
    border-bottom: 3px solid transparent;
    margin-bottom: -2px;
    transition: all 0.15s;
}

.tab.active {
    color: var(--primary);
    border-bottom-color: var(--primary);
}

.tab-badge {
    font-size: 0.75rem;
    background: var(--gray-200);
    padding: 1px 6px;
    border-radius: 8px;
    margin-left: 4px;
}

.tab.active .tab-badge {
    background: #e3f2fd;
    color: var(--primary);
}

.checklist-container {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.checklist-category {
    background: white;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    overflow: hidden;
}

.category-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    font-weight: 600;
    cursor: pointer;
    background: var(--gray-100);
    user-select: none;
}

.category-progress {
    font-size: 0.8rem;
    color: var(--gray-600);
    font-weight: 500;
}

.checklist-item {
    padding: 12px 16px;
    border-top: 1px solid var(--gray-200);
}

.checklist-item.pass { border-left: 4px solid var(--success); }
.checklist-item.fail { border-left: 4px solid var(--danger); }
.checklist-item.notapplicable { border-left: 4px solid var(--gray-300); }

.item-description {
    font-size: 0.9rem;
    margin-bottom: 8px;
}

.item-actions {
    display: flex;
    gap: 8px;
}

.result-btn {
    width: 48px;
    height: 40px;
    border: 2px solid var(--gray-300);
    border-radius: 8px;
    background: white;
    font-size: 1.1rem;
    cursor: pointer;
    transition: all 0.1s;
    display: flex;
    align-items: center;
    justify-content: center;
}

.result-btn:active { transform: scale(0.9); }

.result-btn.pass.selected {
    background: var(--success);
    border-color: var(--success);
    color: white;
}

.result-btn.fail.selected {
    background: var(--danger);
    border-color: var(--danger);
    color: white;
}

.result-btn.na.selected {
    background: var(--gray-600);
    border-color: var(--gray-600);
    color: white;
}

.item-notes { margin-top: 8px; }

.item-notes input {
    width: 100%;
    padding: 8px 12px;
    border: 1px solid var(--gray-300);
    border-radius: 6px;
    font-size: 0.85rem;
}

.photos-container {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.photo-upload-btn {
    display: block;
    width: 100%;
    padding: 16px;
    background: white;
    border: 2px dashed var(--primary);
    border-radius: var(--radius);
    text-align: center;
    font-size: 1rem;
    font-weight: 600;
    color: var(--primary);
    cursor: pointer;
}

.photo-upload-btn input[type="file"] { display: none; }

.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));
    gap: 12px;
}

.photo-card {
    position: relative;
    background: white;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    overflow: hidden;
}

.photo-card img {
    width: 100%;
    height: 120px;
    object-fit: cover;
}

.photo-card input {
    width: 100%;
    padding: 8px;
    border: none;
    border-top: 1px solid var(--gray-200);
    font-size: 0.8rem;
    outline: none;
}

.photo-delete {
    position: absolute;
    top: 4px;
    right: 4px;
    background: rgba(0,0,0,0.6);
    border: none;
    border-radius: 50%;
    width: 28px;
    height: 28px;
    cursor: pointer;
    font-size: 0.8rem;
}

.notes-container textarea {
    resize: vertical;
    min-height: 200px;
}

.empty-state {
    text-align: center;
    padding: 32px 16px;
    color: var(--gray-600);
}

.loading-progress { display: none; }

#blazor-error-ui {
    background: var(--danger);
    color: white;
    padding: 12px;
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 9999;
    display: none;
}

#blazor-error-ui[style] { display: block; }

@media (pointer: coarse) {
    .result-btn {
        min-width: 52px;
        min-height: 44px;
    }

    .checklist-item {
        padding: 14px 16px;
    }
}

